import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "凌晨。她不確定幾點。手機在她接回來之後就沒有再亮過。她不想看時間。時間現在對她沒有用——她不在等什麼，也沒有什麼在等她。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部和年輕警員在問話結束後離開了房間。她被留在裡面坐了十分鐘左右。然後一個她沒見過的警員進來，遞給她一張紙。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "近期不要離開都內。需要離開，先通知我們。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她接過那張紙。上面印著幾行字。她沒有逐行讀。她看見了幾個關鍵詞——「重大參考人」「配合再次問話」「手機資料已備份不得刪除相關訊息」「染血外套暫時作為證物保全」「銀色外殼將送鑑定」「千田浩介死亡已確認死因仍待鑑定」。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她被允許離開了。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是無罪釋放。不是不起訴。是「暫時」。暫時可以走。暫時不是嫌疑人。暫時是重大參考人。暫時不要離開都內。暫時不要刪資料。暫時不要——", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來的時候膝蓋是軟的。不是因為恐懼。是因為坐太久了。她的身體在問話的兩個多小時裡一直維持著同一個姿勢——背挺直，手放在桌上，回答問題。現在姿勢鬆了，肌肉才開始抗議。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走出問話室。走廊很長。燈光是那種省電的冷白色，照得地面反光，像一條被消毒過的河。她的腳步聲在走廊裡彈，一下一下，很規律。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊盡頭有一扇半開的門。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門裡透出來的光比走廊亮。她走過的時候，餘光掃到了門裡面的東西——一面牆上的螢幕。不是筆電。是掛在牆上的監控螢幕。螢幕上有一個定格畫面。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停下了。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不是刻意停下來的。是她的腳先停了，然後她的眼睛才跟上來。像身體比大腦先認出了什麼。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她透過半開的門看那面螢幕。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第七車。監視器角度。從車廂頂部往下拍。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田倒在座位和窗戶的夾角裡。身體前傾，頭垂著，外套被剪開的兩片垂在兩側。他的臉看不清楚——監視器的角度不夠低，只拍到他的頭頂和肩膀。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在他旁邊。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個畫面裡的她。站在千田身側。左手握著銀色外殼。外殼的破邊朝上，在車廂的冷光下反著一道細細的亮線——像刀。她的手上都是血。掌心、指縫、手腕。血在監視器的低解析度畫面裡看起來是黑色的，像她把手浸進了什麼東西裡。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的右手在畫面裡是伸出去的。朝著千田的方向。但監視器的角度看不見她的手貼在他的肋下。它只看見她的手伸向他。它看不見她在壓。它看不見她在止血。它只看見——她的手，伸向一個正在倒下的人。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "畫面裡的她沒有表情。監視器的解析度不夠高，看不清五官。但她看起來——冷靜。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沉默。站在那裡。沒有跑。沒有蹲下。沒有慌張地揮手求救。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只是站著。手裡握著東西。站在一個不再動的人旁邊。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯那不是我。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想移開視線。她的身體在動——頭往回轉，腳準備繼續走。但她的眼睛跟不上。她的眼睛還停在那個畫面上。停在那個站在千田旁邊的女孩身上。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個女孩看起來冷靜、沉默，像早就知道男人會倒下。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪想移開視線，卻發現所有人都正在看那個女孩，而不是她。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是真的有人在看。走廊上只有她。但那面螢幕上的定格畫面，就是所有人接下來會看到的第一個版本。控制中心的人看過。警方看過。日下部看過。鑑識看過。明天，也許檢察官會看。後天，也許更多的人會看。他們都會看見這個畫面。這個站在死者旁邊、手裡握著像刀的東西、滿手是血、沒有在跑的女孩。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們不會看見千田把外殼塞進她手裡的那個動作。因為那段不在中央流裡。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們不會看見外殼裡面的金色接點。因為證物袋外面只寫了「金屬外殼狀物」，不寫裡面有什麼。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們不會看見千田外套內側那塊已經翹起來的白色膠布。因為那是在救護人員剪開外套之後才露出來的，監視器拍不到那個角度。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們只會看見這個畫面。這個定格。這個她。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)畫面少了一段。外殼不像刀。血跡像早已存在。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三件事。她把它們在腦子裡排了一遍。像查核員在整理待核清單。三個矛盾。三個中央流版本回答不了的問題。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一，畫面少了一段。千田把外殼交給她的動作不在中央流裡。她親身經歷了那個動作——他的手指攥住她的手，把外殼壓進她掌心。但中央流裡沒有。她說了。紀錄裡寫的是「朝倉澪承認接觸金屬外殼狀物」。沒有「交付」。沒有「被塞」。只有「接觸」。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二，外殼不像刀。破邊像刀——三角形的、翹起的、反光的。但裡面有金色接點。刀不會有接點。她在放下外殼的那一刻看見了。金色接點整整齊齊，像記憶卡或電子模組的針腳。那不是武器。那是什麼東西的殼。從某個設備上被強行撬下來的殼。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三，血跡像早已存在。千田外套內側的血不是剛剛才開始流的。邊緣發暗，乾涸，像已經在那裡待了很久。那塊白色膠布的黏性已經失效了——不是剛貼的。是撐了很久的。座位上的血痕起點比她以為的更低——不是大腿外側，是肋下往後延伸的方向。他上車的時候就已經在流血了。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個矛盾。但三個矛盾都不在她手上。外殼在證物袋裡。血衣在證物袋裡。畫面在控制中心的系統裡。她什麼都沒有。她只有記憶。記憶不是證據。記憶是她一個人的版本。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她繼續走。走廊的盡頭是一個轉角。轉過去，她聽見了聲音。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是對她說的。是門裡面的。一扇半開的門——不是剛才那扇，是另一扇。站務控制室的門。裡面有人在說話。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.StationStaff, character: "站務主管", dialogue: "事故車明天上午會移到有明車輛基地。車載原始檔要等技術班提取。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停在了門外。沒有刻意停。是那句話裡的幾個字把她絆住了。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)有明車輛基地。車載原始檔。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽見了。她把它記住了。像剛才在車廂裡記住外殼上的 T 和 7 一樣——快門按下去，畫面存進來，之後再想是什麼意思。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "如果中央流少了千田把外殼交給她的那一段。如果控制中心的版本裡，她只是站在那裡、手裡握著東西。如果那段畫面就是所有人最先看到、也最願意相信的版本。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那麼唯一可能證明千田交付外殼的地方，就是事故車上的本地原始檔。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車載原始檔。存在列車的安全資料單元裡。站務室看不了。要等事故車封存，由技術班在有明車輛基地提取出來。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "明天上午。事故車會被移走。原始檔會被技術班提取。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道技術班會不會抽出完整的東西。她不知道原始檔裡有沒有中央流少掉的那一段。她不知道自己能不能碰到那份檔案。她只知道——如果那份檔案存在，如果它記得中央流忘記的事，那它就是唯一能證明她版本的地方。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有決定要闖進有明車輛基地。她還沒有。她只是把這個地名存進了腦子裡。和 T、和 7、和金色接點、和血痕起點、和「不要救東京」放在一起。放在同一個越來越滿的、她還沒有時間整理的清單裡。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她繼續走。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊盡頭的門開著。外面是深夜的街道。冷風灌進來，帶著混凝土和瀝青的味道。她走出去的那一刻，冷空氣打在她臉上，像一盆水潑過來。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在警署外面的台階上。身上穿著站務給的那件灰色薄外套。斜背包掛在肩上。手機在外側口袋裡。小鏡子在內層的小布套裡。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她什麼都沒有。她只有記憶、一台被備份過的手機、和一面還沒有被任何人收走的鏡子。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後傳來腳步聲。她沒有回頭。她知道是誰。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部走到她旁邊。他沒有站得很近。保持著一個手臂的距離。他點了一根菸。她聞到了菸味。她不知道他抽菸。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "第一份畫面最麻煩。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他吐了一口煙。煙在冷空氣裡散得很慢。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "後面的人都會照著它問問題。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說完這句話，把菸夾在指間，沒有再說。他看著深夜的街道。澪也看著深夜的街道。兩個人都沒有在看對方。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯那個畫面不是全部。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "我知道。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說「我知道」的時候，語氣很平。太平了。平到她不確定他是在說「我相信你」，還是在說「我知道畫面不是全部，但那不重要，因為所有人都會先相信畫面」。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉頭看他。他的側臉在路燈下很硬。下顎的線條、顴骨的陰影、太陽穴旁邊那幾根灰白的頭髮。他看起來很累。眼睛下面的暗圈比她上次見到他的時候更深。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "你知道些什麼。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回答。他把菸放到嘴邊，吸了一口，吐出來。煙在他和她之間飄了一秒，然後被風帶走。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "回家。不要離開都內。不要刪手機裡的東西。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不是在問程序。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "我在回答程序。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把菸按滅在台階旁邊的金屬菸灰缸裡。動作很慢。像在給她時間消化那句話的意思——他只回答程序。程序以外的事，他不說。不是不知道。是不說。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉身往回走。走了兩步，停了。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "⋯⋯妳父親以前也是這樣。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯什麼？", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭。他沒有解釋。他只是說了這半句話，然後繼續走。腳步聲往警署裡面去了。門開了，又關了。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在台階上。風吹著她。灰色外套太薄了，冷氣從領口灌進來。她的手指縮進袖口裡。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)妳父親以前也這樣。這樣是哪樣。", background: Background.Chapter_3_Ch3_Act6_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道。她不知道他指的是什麼。她不知道她父親和這件事有什麼關係。她不知道日下部為什麼每次提到她父親的時候，聲音都會變——不是變軟，是變深。像在說一個他已經想了很久、但從來沒有對任何人說完的東西。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道的事太多了。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走下台階。深夜的街道很空。路燈把她的影子拉得很長。她走了幾步，然後停下來。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她回頭看了一眼警署的門。門是關著的。門裡面的燈還亮著。她知道那面螢幕還亮著。那個定格畫面還停在那裡。千田倒在座位邊。她站在他身旁。她左手握著銀色外殼。外殼破邊在冷光下像刀。她手上都是血。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監視器裡的她握著銀色外殼，站在千田浩介身邊。那個女孩看起來冷靜、沉默，像早就知道男人會倒下。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪想移開視線，卻發現所有人都正在看那個女孩，而不是她。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉過身。繼續走。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走進深夜裡。背後是警署的燈光，面前是空的街道。她的斜背包裡有一面小鏡子、一台被備份過的手機、和一個她還不知道怎麼用的地名——有明車輛基地。", background: Background.Chapter_3_Ch3_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她什麼都沒有。但她知道下一段路在哪裡了。", background: Background.Chapter_3_Ch3_Act6_S1 },
];
